const text = $json.body.message.text; // "/start NONCE_TOKEN_HERE"
const token = text.split(' ')[1] || null;
const chatId = $json.body.message.chat.id;
return [{ json: { token, chatId } }];

// Get the input from the previous node (Extract Chat Text)
const input = $input.first().json;

// Debug: Log what we received
console.log('Extract Shared Location - Input:', JSON.stringify(input, null, 2));

return [{
  json: {
    // PRESERVE ALL DATA FROM THE INPUT
    chatId: input.chatId,
    userId: input.userId,
    text: input.text || '',
    username: input.username || 'User',
    lat: input.lat,
    lon: input.lon,
    hasLocation: input.hasLocation || false,
    isSensitive: input.isSensitive || false,
    isAirQualityQuestion: input.isAirQualityQuestion || false,
    justSharedLocation: input.justSharedLocation || false,
    // Flag for the DB insert
    storeLocation: true
  }
}];

const message = $json.body.message;
const location = message.location || null;
const text = message.text || '';
const chatId = message.chat.id;
const userId = message.from.id.toString();

const hasLocation = !!location;
const lat = location ? location.latitude : null;
const lon = location ? location.longitude : null;

const result = [{
  json: {
    chatId: chatId,
    userId: userId,
    text: text,
    username: message.from.username || 'User',
    lat: lat,
    lon: lon,
    hasLocation: hasLocation,
    isSensitive: text.toLowerCase().includes('sensitive') || 
                 text.toLowerCase().includes('sensitiv') ||
                 text.toLowerCase().includes('asthma') ||
                 text.toLowerCase().includes('breathing'),
    isAirQualityQuestion: text.toLowerCase().includes('air') || 
                          text.toLowerCase().includes('aqi') || 
                          text.toLowerCase().includes('pm2.5') ||
                          text.toLowerCase().includes('haze') ||
                          text.toLowerCase().includes('quality'),
    justSharedLocation: hasLocation
  }
}];

// Debug log
console.log('Extract Chat Text output:', JSON.stringify(result, null, 2));

return result;

