parameters.jsCode:
const original = $('Extract Chat Text').first().json;

let storedLocation = null;
try {
  const dbResult = $('Get Relevant User Coordinates Session Based').first().json;
  if (dbResult && dbResult.lat !== undefined) storedLocation = dbResult;
} catch (e) {}

const lat = original.lat || (storedLocation ? storedLocation.lat : null);
const lon = original.lon || (storedLocation ? storedLocation.lon : null);

return [{
  json: {
    chatId: original.chatId,
    userId: original.userId,
    text: original.text || '',
    username: original.username || 'User',
    lat,
    lon,
    hasLocation: !!(lat && lon),
    isSensitive: original.isSensitive || false,
    isAirQualityQuestion: original.isAirQualityQuestion || false,
    justSharedLocation: original.justSharedLocation || false,
    locationSource: original.lat ? 'current_message' : 'stored'
  }
}];

parameters.query:
select label, ST_X(location::geometry) as lon, ST_Y(location::geometry) as lat
from favorite_locations
where user_id = $1;

